parameters.jsCode:
const root = $('Webhook Dispute Resolved').first().json;
const b = root.body || root;
const RESOLUTION_LABELS = { refund_full: 'Полный возврат заказчику', release_payment: 'Выплата исполнителю' };
const order_id = String(b.order_id || '—');
const dispute_id = String(b.dispute_id || '—');
const resolution = String(b.resolution || '');
const resolution_label = RESOLUTION_LABELS[resolution] || resolution || 'не указано';
const resolved_at = String(b.resolved_at || new Date().toISOString());
const customer_phone = String(b.customer_phone || '—');
const executor_phone = String(b.executor_phone || '—');

// Сообщение админу: полный контекст
const adminText = `\u2705 *Спор решён*\n\n\uD83C\uDD94 Заказ: ${order_id}\n\uD83D\uDD16 Спор: ${dispute_id}\n\u2696\uFE0F Решение: ${resolution_label}\n\uD83D\uDCDE Заказчик: ${customer_phone}\n\uD83D\uDCDE Исполнитель: ${executor_phone}\n\uD83D\uDD52 Время: ${resolved_at}\n\n\u26A1 Свяжитесь с обеими сторонами для исполнения решения.`;

// Сообщение заказчику (если refund_full — хорошая новость)
const customerText = resolution === 'refund_full'
  ? `\u2705 *Спор по заказу ${order_id} разрешён в вашу пользу*\n\nАдминистратор принял решение о полном возврате средств. Мы свяжемся с вами для уточнения реквизитов.`
  : `\u2139\uFE0F *Спор по заказу ${order_id} закрыт*\n\nАдминистратор принял решение о выплате исполнителю. Если у вас остались вопросы — ответьте на это сообщение.`;

// Сообщение исполнителю
const executorText = resolution === 'release_payment'
  ? `\u2705 *Спор по заказу ${order_id} разрешён в вашу пользу*\n\nВыплата будет переведена в течение рабочего дня.`
  : `\u2139\uFE0F *Спор по заказу ${order_id} закрыт*\n\nАдминистратор принял решение о возврате средств заказчику. Свяжитесь с поддержкой для уточнения деталей.`;

return [{ json: { adminText, customerText, executorText, customer_phone, executor_phone } }];

